light_room_header.label:
[[[
  const ids = variables.light_ids || [];
  const on = ids.filter(id => states[id] && states[id].state === 'on').length;
  const total = ids.length;
  const nameStyle = 'font-size:13px;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--kis-lights-room-name,#eef2f8)';
  const countStyle = 'font-size:13px;font-weight:600;letter-spacing:0.04em;color:var(--kis-lights-room-count,#8a95a6)';
  return '<div style="display:flex;align-items:baseline;justify-content:space-between;width:100%;padding:0 2px 8px;border-bottom:1px solid var(--kis-lights-row-rule,rgba(255,255,255,0.06));">' +
         '<span style="' + nameStyle + '">' + (variables.room_name || '') + '</span>' +
         '<span style="' + countStyle + '">' + on + '/' + total + ' on</span>' +
         '</div>';
]]]

