custom_fields.bar:
[[[
  const on = entity.state === 'on';
  const hasDim = entity && entity.attributes && (typeof entity.attributes.brightness === 'number');
  const raw = hasDim ? (entity.attributes.brightness || 0) : 0;
  const pct = on ? (hasDim ? Math.max(3, Math.round((raw / 255) * 100)) : 100) : 0;
  const track = 'var(--kis-lights-bar-track, rgba(255,255,255,0.08))';
  const fill = 'var(--kis-lights-bar-fill, #f5a623)';
  return '<div style="position:relative;width:100%;height:8px;border-radius:4px;background:' + track + ';overflow:hidden">' +
         '<div style="position:absolute;top:0;bottom:0;left:0;width:' + pct + '%;background:' + fill + ';border-radius:4px;transition:width 180ms ease"></div>' +
         '</div>';
]]]

cards.name:
[[[
      const CAM_LABELS = {
        doorbell: states['camera.doorbell']?.attributes?.friendly_name || 'Front Door',
        living_room: states['camera.nest_cam_2']?.attributes?.friendly_name || "Ben's Room",
        izzy: states['camera.nest_cam_1']?.attributes?.friendly_name || 'Living Room',
        nanit_benjamin: states['camera.nanit_benjamin']?.attributes?.friendly_name || "Ben's Bed",
        nanit_travel: states['camera.nanit_travel']?.attributes?.friendly_name || 'Dining Room',
      };
      const cam = states['sensor.priority_camera']?.state;
      if (!cam || cam === 'none') return 'PRIORITY DISPLAY';
      const label = CAM_LABELS[cam] || cam;
      return 'MOTION: ' + label.toUpperCase();
    ]]]

name.color:
[[[
    var cam = states['sensor.priority_camera'] ? states['sensor.priority_camera'].state : 'none';
    var idx = states['input_number.priority_slide_index'] ? Math.round(parseFloat(states['input_number.priority_slide_index'].state)) : 0;
    return (cam !== 'none' && idx === 0) ? '#f04060' : 'var(--kis-section-label, #4a5570)';
  ]]]

cards.label:
[[[
    if (states['sensor.tesla_battery_level']) {
      var b = states['sensor.tesla_battery_level'].state;
      var r = states['sensor.tesla_range'] ? ' · ' + Math.round(parseFloat(states['sensor.tesla_range'].state)) + ' mi' : '';
      return b + '%' + r;
    }
    return 'Setup Required';
  ]]]

cards.icon:
[[[
    var c = entity.state;
    var m = {'sunny':'mdi:weather-sunny','clear-night':'mdi:weather-night','cloudy':'mdi:weather-cloudy','partlycloudy':'mdi:weather-partly-cloudy','rainy':'mdi:weather-pouring','pouring':'mdi:weather-pouring','snowy':'mdi:weather-snowy','fog':'mdi:weather-fog','windy':'mdi:weather-windy','lightning':'mdi:weather-lightning','lightning-rainy':'mdi:weather-lightning-rainy','hail':'mdi:weather-hail'};
    return m[c] || 'mdi:weather-cloudy';
  ]]]

cards.name:
[[[
    var t = entity.attributes.temperature;
    return (t == null) ? '--' : (Math.round(t) + '°F');
  ]]]

cards.label:
[[[
    var s = (entity.state || '').replace(/-/g,' ').replace(/\b\w/g, function(c){return c.toUpperCase();});
    var h = entity.attributes.humidity;
    var w = entity.attributes.wind_speed;
    var parts = [s];
    if (h != null) parts.push(h + '% hum');
    if (w != null) parts.push(Math.round(w) + ' mph');
    return parts.join(' · ');
  ]]]

icon.color:
[[[
        var c = entity.state;
        var m = {'sunny':'#f5a623','clear-night':'#9d6ef0','cloudy':'#8a9ab8','partlycloudy':'#4d8ef0','rainy':'#4d8ef0','pouring':'#4d8ef0','snowy':'#eef2f8','fog':'#8a9ab8','windy':'#8a9ab8','lightning':'#f5a623','lightning-rainy':'#f5a623'};
        return m[c] || '#8a9ab8';
      ]]]

